// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useRef, useMemo } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// ── TYPES: define local types and interfaces here ──

// ── CONSTANTS: define constants, config, mappings here ──

// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──

function useComponent(props: Props) {
  // ── STATE: define useState hooks here ──
  // No additional state needed — all data comes from props

  // ── MEMOS: define useMemo for derived/computed values ──
  const weatherIcon = useMemo(() => {
    const condition = (props.condition || '').toLowerCase();
    if (condition.includes('sunny') || condition.includes('clear')) return '☀️';
    if (condition.includes('cloud')) return '☁️';
    if (condition.includes('rain')) return '🌧️';
    if (condition.includes('snow')) return '❄️';
    if (condition.includes('wind')) return '💨';
    if (condition.includes('fog')) return '🌫️';
    return '🌤️';
  }, [props.condition]);

  // ── CALLBACKS: define useCallback for event handlers ──
  // No event handlers needed — purely display component

  return {
    weatherIcon,
  };
}

export default function Component(props: Props) {
  const { weatherIcon } = useComponent(props);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6, 24px)" center>
      <Stack gap="var(--ggui-spacing-6, 24px)" align="center">
        {/* HEADER */}
         <Stack gap="var(--ggui-spacing-2, 8px)" align="center">
          <Heading level={2}>{props.city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {props.condition}
          </Text>
        </Stack>

        {/* MAIN WEATHER CARD */}
         <Card shadow="md" padding="var(--ggui-spacing-8, 32px)" radius="lg">
           <Stack gap="var(--ggui-spacing-6, 24px)" align="center">
            {/* WEATHER ICON AND TEMPERATURE */}
             <Stack gap="var(--ggui-spacing-4, 16px)" align="center">
              <Text size="4xl">{weatherIcon}</Text>
              <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)" align="center">
                {props.temperature}°{props.unit}
              </Heading>
            </Stack>

            {/* DETAILS ROW */}
             <Row gap="var(--ggui-spacing-8, 32px)" justify="center" align="center">
              {/* HUMIDITY */}
               <Stack gap="var(--ggui-spacing-2, 8px)" align="center">
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-500, #0ea5e9)" />
                 <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Humidity
                  </Text>
                  <Text variant="bodySmall" weight="semibold">
                    {props.humidity}%
                  </Text>
                </Stack>
              </Stack>

              {/* WIND SPEED */}
               <Stack gap="var(--ggui-spacing-2, 8px)" align="center">
                <Icon name="wind" size={24} color="var(--ggui-color-success-500, #22c55e)" />
                 <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Wind
                  </Text>
                  <Text variant="bodySmall" weight="semibold">
                    {props.windSpeed} m/s
                  </Text>
                </Stack>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-DAY FORECAST */}
         <Stack gap="var(--ggui-spacing-3, 12px)" style={{ width: '100%' }}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            5-Day Forecast
          </Text>
           <Row gap="var(--ggui-spacing-3, 12px)" justify="start" wrap>
             {(props.forecast || []).map((day, idx) => (
              <Card
                key={idx}
                shadow="sm"
                 padding="var(--ggui-spacing-4, 16px)"
                radius="md"
                 style={{ flex: '0 1 calc(20% - var(--ggui-spacing-3, 12px))', minWidth: '100px' }}
              >
                 <Stack gap="var(--ggui-spacing-2, 8px)" align="center" justify="center">
                  <Text variant="label" weight="semibold" align="center">
                    {day.day || `Day ${idx + 1}`}
                  </Text>
                  <Text size="2xl">{day.icon || '🌤️'}</Text>
                   <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
                    <Text variant="bodySmall" weight="semibold">
                       {day.high ?? 'N/A'}°
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                       {day.low ?? 'N/A'}°
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Container>
  );
}

