// prettier-ignore-start
import React, { useState, useCallback, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// ── TYPES: define local types and interfaces here ──

// ── CONSTANTS: define constants, config, mappings here ──

// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // ── STATE: define useState hooks here ──
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // ── MEMOS: define useMemo for derived/computed values ──
  const nameError = name.trim() === '' ? 'Name is required' : '';
  const emailError = email.trim() === '' ? 'Email is required' : !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) ? 'Invalid email format' : '';
  const isStep1Valid = !nameError && !emailError;
  const isStep2Valid = satisfaction !== '';
  const isStep3Valid = features.length > 0;
  const isStep4Valid = true; // Comments are optional

  // ── CALLBACKS: define useCallback for event handlers ──
  const handleNext = useCallback(() => {
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleFeatureToggle = useCallback((feature: string) => {
    setFeatures(prev => 
      prev.includes(feature) ? prev.filter(f => f !== feature) : [...prev, feature]
    );
  }, []);

  const handleSubmit = useCallback(() => {
    if (isStep1Valid && isStep2Valid) {
      const satisfactionNum = satisfaction ? parseInt(satisfaction, 10) : 0;
      submit({
        name: name.trim(),
        email: email.trim(),
        satisfaction: satisfactionNum,
        features,
        comments: comments.trim()
      });
    }
  }, [name, email, satisfaction, features, comments, isStep1Valid, isStep2Valid, submit]);

  return { currentStep, setCurrentStep, name, setName, email, setEmail, satisfaction, setSatisfaction, features, handleFeatureToggle, comments, setComments, handleNext, handleBack, handleSubmit, nameError, emailError, isStep1Valid, isStep2Valid, isStep3Valid, isStep4Valid };
}

export default function Component(props: Props) {
  const { currentStep, setCurrentStep, name, setName, email, setEmail, satisfaction, setSatisfaction, features, handleFeatureToggle, comments, setComments, handleNext, handleBack, handleSubmit, nameError, emailError, isStep1Valid, isStep2Valid, isStep3Valid, isStep4Valid } = useComponent(props);

  const satisfactionLabels = props.satisfactionLabels && props.satisfactionLabels.length > 0 ? props.satisfactionLabels : ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'];
  const satisfactionOptions = satisfactionLabels.map((label, idx) => ({
    value: String(idx + 1),
    label: `${idx + 1} - ${label}`
  }));

  const featureOptions = props.featureOptions && props.featureOptions.length > 0 ? props.featureOptions : [];
  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16}>
        {/* PROGRESS BAR */}
        <Stack gap={8}>
          <Heading level={2}>Multi-Step Survey</Heading>
          <Text variant="bodySmall">Step {currentStep} of 4</Text>
          <Progress value={currentStep} max={4} variant="default" size="md" />
        </Stack>
        {/* STEP 1: NAME & EMAIL */}
        {currentStep === 1 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Name"
                value={name}
                onChange={setName}
                placeholder="Enter your full name"
                required
                error={nameError}
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                placeholder="Enter your email address"
                required
                error={emailError}
              />
            </Stack>
          </Card>
        )}

        {/* STEP 2: SATISFACTION RATING */}
        {currentStep === 2 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* STEP 3: FEATURE INTERESTS */}
        {currentStep === 3 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>What features interest you?</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Select all that apply</Text>
              <Stack gap={12}>
                {featureOptions && Array.isArray(featureOptions) && featureOptions.map(feature => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 4: FINAL REVIEW */}
        {currentStep === 4 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap={12}>
                <Box paddingY={8} borderRadius={4} background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={12}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                  <Text variant="body">{name}</Text>
                </Box>
                <Box paddingY={8} borderRadius={4} background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={12}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                  <Text variant="body">{email}</Text>
                </Box>
                <Box paddingY={8} borderRadius={4} background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={12}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction Rating</Text>
                  <Text variant="body">{satisfaction && satisfactionLabels && satisfactionLabels.length > parseInt(satisfaction, 10) - 1 ? `${satisfaction} - ${satisfactionLabels[parseInt(satisfaction, 10) - 1]}` : 'Not selected'}</Text>
                </Box>
                <Box paddingY={8} borderRadius={4} background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={12}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Interested Features</Text>
                  <Text variant="body">{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                </Box>
                <Box paddingY={8} borderRadius={4} background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={12}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                  <Text variant="body">{comments || '(No comments)'}</Text>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}
        {/* NAVIGATION BUTTONS */}
        <Row gap={12} justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
           {currentStep < 4 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !isStep1Valid) ||
                (currentStep === 2 && !isStep2Valid) ||
                (currentStep === 3 && !isStep3Valid)
              }
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              disabled={!isStep1Valid || !isStep2Valid}
            >
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// ── TYPES: define local types and interfaces here ──
type TaskWithUI = { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee?: string; column: string; dueDate?: string };

// ── CONSTANTS: define constants, config, mappings here ──
const PRIORITY_COLORS: Record<'low' | 'medium' | 'high', 'default' | 'warning' | 'error'> = {
  low: 'default',
  medium: 'warning',
  high: 'error',
};

// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──
function TaskCard({ task, onMove, onSave }: { task: TaskWithUI; onMove: (newColumn: string) => void; onSave: (newTitle: string) => void }) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title);
  const [showMoveDropdown, setShowMoveDropdown] = useState(false);

  const handleEdit = () => setIsEditing(true);
  const handleSave = () => {
    onSave(editTitle);
    setIsEditing(false);
  };
  const handleCancel = () => {
    setEditTitle(task.title);
    setIsEditing(false);
  };

  const columns = ['todo', 'in-progress', 'done'];
  const columnNames: Record<string, string> = { 'todo': 'To Do', 'in-progress': 'In Progress', 'done': 'Done' };

  return (
    <Card padding={12} shadow="sm" radius="md" style={isEditing ? { borderLeft: '3px solid var(--ggui-color-primary-600, #0284c7)' } : {}}>
      <Stack gap={8}>
        {isEditing ? (
          <Input label="Task title" value={editTitle} onChange={setEditTitle} />
        ) : (
          <Text variant="body" weight="semibold" as={Clickable} onClick={handleEdit} style={{ cursor: 'pointer' }}>
            {task.title}
          </Text>
        )}
        <Row gap={8} align="center" justify="between">
          <Stack gap={4} direction="horizontal" align="center">
            <Badge variant={PRIORITY_COLORS[task.priority || 'medium']} size="sm">{task.priority || 'medium'}</Badge>
            {task.assignee && <Avatar name={task.assignee} size="sm" shape="circle" />}
          </Stack>
          {isEditing ? (
            <Row gap={4}>
              <Button size="xs" variant="ghost" onClick={handleCancel}>Cancel</Button>
              <Button size="xs" variant="primary" onClick={handleSave}>Save</Button>
            </Row>
          ) : (
            <Row gap={4}>
              <Button size="xs" variant="ghost" onClick={handleEdit}>Edit</Button>
              <Dropdown
                trigger={<Button size="xs" variant="ghost" rightIcon={<Icon name="chevron-down" size={14} />}>Move</Button>}
                options={columns.filter((c) => c !== task.column).map((c) => ({ value: c, label: columnNames[c] }))}
                value={task.column}
                onChange={(newCol) => { onMove(newCol); setShowMoveDropdown(false); }}
                placement="bottom-end"
              />
            </Row>
          )}
        </Row>
        {task.dueDate && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{task.dueDate}</Text>}
      </Stack>
    </Card>
  );
}

function Column({ col, tasks, onMoveTask, onAddTask, onSaveTask }: { col: { id: string; name: string }; tasks: TaskWithUI[]; onMoveTask: (taskId: string, newColumn: string) => void; onAddTask: (title: string, priority: string) => void; onSaveTask: (taskId: string, newTitle: string) => void }) {
  const [showAddForm, setShowAddForm] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState('medium');

  const handleAdd = () => {
    if (newTitle.trim()) {
      onAddTask(newTitle, newPriority);
      setNewTitle('');
      setNewPriority('medium');
      setShowAddForm(false);
    }
  };

  const isToDoColumn = col.id === 'todo';

  return (
    <Card padding={16} shadow="sm" radius="lg" style={{ flex: 1, minWidth: '280px', maxHeight: '70vh', overflow: 'auto' }}>
      <Stack gap={12}>
        <Stack gap={4}>
          <Heading level={4}>{col.name}</Heading>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{tasks.length} task{tasks.length !== 1 ? 's' : ''}</Text>
        </Stack>
        <Divider margin={8} />
        <Stack gap={8}>
          {tasks.map((task) => (
            <TaskCard key={task.id} task={task} onMove={(newCol) => onMoveTask(task.id, newCol)} onSave={(newTitle) => onSaveTask(task.id, newTitle)} />
          ))}
        </Stack>
        <Divider margin={8} />
        {isToDoColumn && (
          <>
            {showAddForm ? (
              <Stack gap={8}>
                <Input label="Task title" placeholder="Enter task title" value={newTitle} onChange={setNewTitle} />
                <Select label="Priority" value={newPriority} onChange={setNewPriority} options={[{ value: 'low', label: 'Low' }, { value: 'medium', label: 'Medium' }, { value: 'high', label: 'High' }]} />
                <Row gap={8} justify="end">
                  <Button size="sm" variant="ghost" onClick={() => { setShowAddForm(false); setNewTitle(''); setNewPriority('medium'); }}>Cancel</Button>
                  <Button size="sm" variant="primary" onClick={handleAdd}>Add</Button>
                </Row>
              </Stack>
            ) : (
              <Button size="sm" variant="secondary" fullWidth onClick={() => setShowAddForm(true)}>+ Add Task</Button>
            )}
          </>
        )}
      </Stack>
    </Card>
  );
}

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // ── STATE: define useState hooks here ──
  const [tasks, setTasks] = useState<TaskWithUI[]>(
    (props.tasks || []).map((t) => ({
      id: t.id || `task-${Date.now()}-${Math.random()}`,
      title: t.title || 'Untitled',
      priority: t.priority || 'medium',
      assignee: t.assignee,
      column: t.column || 'todo',
      dueDate: t.dueDate,
    }))
  );

  // Apply stream updates to tasks
  React.useEffect(() => {
    if (taskChanged.latest?.task) {
      const updated = taskChanged.latest.task;
      if (taskChanged.latest.action === 'delete' && updated.id) {
        setTasks((prev) => prev.filter((t) => t.id !== updated.id));
      } else if (updated.id) {
        setTasks((prev) => {
          const existing = prev.find((t) => t.id === updated.id);
          if (existing) {
            return prev.map((t) => (t.id === updated.id ? { ...t, ...updated } : t));
          }
          return [...prev, updated as TaskWithUI];
        });
      }
    }
  }, [taskChanged.latest]);

  // ── CALLBACKS: define useCallback for event handlers ──
  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t)));
      taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
    },
    [taskUpdate]
  );

  const handleAddTask = useCallback(
    (title: string, priority: string = 'medium', column: string = 'todo') => {
      const newId = `task-${Date.now()}-${Math.random()}`;
      const newTask: TaskWithUI = {
        id: newId,
        title,
        priority: (priority || 'medium') as 'low' | 'medium' | 'high',
        column,
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newId, data: { column } });
    },
    [taskUpdate]
  );

  const handleSaveTask = useCallback(
    (taskId: string, newTitle: string) => {
      setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t)));
      taskUpdate({ action: 'edit', taskId, data: { column: tasks.find((t) => t.id === taskId)?.column || 'todo' } });
    },
    [taskUpdate, tasks]
  );

  const completedCount = tasks.filter((t) => t.column === 'done').length;
  const totalCount = tasks.length;

  return { taskUpdate, taskChanged, tasks, handleMoveTask, handleAddTask, handleSaveTask, completedCount, totalCount };
}

export default function Component(props: Props) {
  const { tasks, handleMoveTask, handleAddTask, handleSaveTask, completedCount, totalCount } = useComponent(props);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16}>
        {/* HEADER */}
        <Stack gap={8}>
          <Heading level={1}>Task Board</Heading>
          <Box padding={12} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius={8}>
            <Row gap={16} justify="between">
              <Text variant="body">
                <Text is="span" weight="semibold">Total:</Text> {totalCount} tasks
              </Text>
              <Text variant="body">
                <Text is="span" weight="semibold">Completed:</Text> {completedCount} / {totalCount}
              </Text>
              {totalCount > 0 && (
                <Progress value={completedCount} max={totalCount} variant="success" size="sm" />
              )}
            </Row>
          </Box>
        </Stack>

        {/* KANBAN BOARD */}
        <Row gap={16} align="start" style={{ overflowX: 'auto', paddingBottom: '16px' }}>
          {(props.columns || []).map((col) => {
            const colId = col.id || 'unknown';
            const colTasks = tasks.filter((t) => t.column === colId);
            return (
              <Column
                key={colId}
                col={{ id: colId, name: col.name || 'Column' }}
                tasks={colTasks}
                onMoveTask={handleMoveTask}
                onAddTask={(title, priority) => handleAddTask(title, priority, colId)}
                onSaveTask={handleSaveTask}
              />
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

