function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // ── STATE: define useState hooks here ──
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState<string>('description');

  // ── MEMOS: define useMemo for derived/computed values ──
  const isOutOfStock = !props.product.stock || props.product.stock <= 0;
  const maxQuantity = props.product.stock || 1;
  const stockStatus = (props.product.stock || 0) > 5 ? 'In Stock' : 'Low Stock';
  const stockVariant = (props.product.stock || 0) > 5 ? 'success' : 'warning';

  // ── CALLBACKS: define useCallback for event handlers ──
  const handleQuantityChange = useCallback((value: number) => {
    setQuantity(Math.max(1, Math.min(value, maxQuantity)));
  }, [maxQuantity]);

  const handleAddToCart = useCallback(() => {
    if (!isOutOfStock && props.product.id) {
      addToCart({ productId: props.product.id, quantity });
      setQuantity(1);
    }
  }, [isOutOfStock, props.product.id, quantity, addToCart]);

  return {
    quantity,
    setQuantity: handleQuantityChange,
    activeTab,
    setActiveTab,
    isOutOfStock,
    maxQuantity,
    stockStatus,
    stockVariant,
    handleAddToCart,
  };
}
}

