// Helper: Group consecutive messages by sender
function groupMessagesBySender(messages: Array<{ sender?: string; text?: string; timestamp?: string }>) {
  const groups: Array<{ sender: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
  for (const msg of messages) {
    const sender = msg.sender || 'Unknown';
    if (groups.length > 0 && groups[groups.length - 1].sender === sender) {
      groups[groups.length - 1].messages.push(msg);
    } else {
      groups.push({ sender, messages: [msg] });
    }
  }
  return groups;
}

function useComponent(props: Props) {
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // STATE: define useState hooks here
  const [messageText, setMessageText] = useState('');
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-append new messages from stream
  React.useEffect(() => {
    if (message.latest) {
      setAllMessages(prev => [...prev, message.latest]);
    }
  }, [message.latest]);

  // Auto-scroll to bottom on new messages
  React.useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages]);

  // CALLBACKS: define useCallback for event handlers
  const handleSendMessage = useCallback(() => {
    if (messageText.trim()) {
      sendMessage({ text: messageText, timestamp: new Date().toISOString() });
      setMessageText('');
    }
  }, [messageText, sendMessage]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  return {
    sendMessage,
    message,
    typing,
    messageText,
    setMessageText,
    allMessages,
    handleSendMessage,
    handleKeyDown,
    messagesEndRef,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  // Determine if there's an active typing indicator (another user)
  const isOtherUserTyping = state.typing.latest?.active && state.typing.latest?.sender !== props.currentUser;

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16} align="stretch">
        {/* HEADER */}
        <Stack gap={8}>
