            <Badge variant="primary" size="md">{props.participantCount} participants</Badge>
          </Stack>
        </Stack>

        {/* MESSAGE LIST */}
        <Card padding={16} shadow="sm" style={{ display: 'flex', flexDirection: 'column', height: '400px', overflow: 'auto' }}>
          <Stack gap={12} align="stretch">
            {groupMessagesBySender(state.allMessages).map((group, groupIdx) => {
              const isCurrentUser = group.sender === props.currentUser;
              return (
                <Box key={groupIdx} padding={12} borderRadius="8px" background={isCurrentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'} style={{ alignSelf: isCurrentUser ? 'flex-end' : 'flex-start', maxWidth: '70%', wordWrap: 'break-word' }}>
                  <Stack gap={8} align={isCurrentUser ? 'end' : 'start'}>
                    <Text variant="label" color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}>
                      {group.sender}
                    </Text>
                    <Stack gap={4} align={isCurrentUser ? 'end' : 'start'}>
                      {group.messages.map((msg, msgIdx) => {
                        const timestamp = msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '';
                        return (
                          <div key={msgIdx}>
                            <Text variant="body" color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface, #18181b)'}>
                              {msg.text || '(empty message)'}
                            </Text>
                            {timestamp && (
                              <Text variant="caption" color={isCurrentUser ? 'rgba(255,255,255,0.8)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}>
                                {timestamp}
                              </Text>
                            )}
                          </div>
                        );
                      })}
                    </Stack>
                  </Stack>
                </Box>
              );
            })}
            {isOtherUserTyping && (
              <Box padding={12} style={{ alignSelf: 'flex-start' }}>
                <Stack direction="horizontal" gap={4} align="center">
                  <Spinner size={16} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {state.typing.latest?.sender || 'Someone'} is typing…
                    </Text>
                  </Text>
                </Stack>
              </Box>
            )}
            <div ref={state.messagesEndRef} />
          </Stack>
        </Card>

        {/* INPUT AREA */}
        <Stack direction="horizontal" gap={8} align="stretch">
          <TextArea
            label="Message"
            value={state.messageText}
            onChange={state.setMessageText}
            onKeyDown={state.handleKeyDown}
            placeholder="Type your message (Enter to send, Shift+Enter for new line)"
            rows={3}
          />
          <Button
            variant="primary"
            size="md"
            onClick={state.handleSendMessage}
            disabled={!state.messageText.trim()}
            style={{ alignSelf: 'flex-end', minWidth: '100px' }}
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

