// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// ── TYPES: define local types and interfaces here ──
interface StockData {
  symbol: string;
  name: string;
  price: number;
  change: number;
  changePercent: number;
}

function StockCard({ stock, isHighlighted, changeColor }: { stock: StockData; isHighlighted: boolean; changeColor: string }) {
  const isPositive = stock.changePercent >= 0;
  const borderColor = isHighlighted ? changeColor : 'var(--ggui-color-outlineVariant, #e4e4e7)';
  return (
    <Card
      key={stock.symbol}
      padding={16}
      shadow="sm"
      radius="md"
      style={{
        borderWidth: '2px',
        borderStyle: 'solid',
        borderColor,
        transition: 'all 200ms ease-in-out',
        animation: isHighlighted ? 'ggui-fadeIn 400ms ease-out' : 'none',
        background: isHighlighted
          ? isPositive
            ? 'var(--ggui-color-success-50, #f0fdf4)'
            : 'var(--ggui-color-error-50, #fef2f2)'
          : 'var(--ggui-color-surface, #ffffff)',
      }}
    >
      <Stack gap={12}>
        <Stack gap={4}>
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">{stock.symbol}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{stock.name}</Text>
        </Stack>
        <Stack gap={2}>
          <Text variant="body" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">${stock.price.toFixed(2)}</Text>
        </Stack>
        <Stack direction="horizontal" gap={8} align="center">
          <Stack direction="horizontal" gap={4} align="center">
            <Icon name={isPositive ? 'arrow-up' : 'arrow-down'} size={16} color={changeColor} />
            <Text variant="body" weight="semibold" color={changeColor}>{stock.change.toFixed(2)}</Text>
          </Stack>
          <Text variant="body" weight="semibold" color={changeColor}>{isPositive ? '+' : ''}{stock.changePercent.toFixed(2)}%</Text>
        </Stack>
      </Stack>
    </Card>
  );
}

function useComponent(props: Props) {
  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // ── STATE: define useState hooks here ──
  const [stocks, setStocks] = useState<StockData[]>([]);
  const [lastUpdatedTime, setLastUpdatedTime] = useState<Date | null>(null);
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());

  // Initialize stocks from props
  React.useEffect(() => {
    if (props.stocks && props.stocks.length > 0) {
      setStocks(
        props.stocks.map((s) => ({
          symbol: s.symbol || '',
          name: s.name || '',
          price: s.price || 0,
          change: s.change || 0,
          changePercent: s.changePercent || 0,
        }))
      );
    }
  }, [props.stocks]);

  // Merge stream price updates into local state
  React.useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prev) =>
        prev.map((stock) =>
          stock.symbol === update.symbol
            ? {
                ...stock,
                price: update.price ?? stock.price,
                change: update.change ?? stock.change,
                changePercent: update.changePercent ?? stock.changePercent,
              }
            : stock
        )
      );
      // Highlight the updated stock
      setHighlightedSymbols((prev) => new Set(prev).add(update.symbol || ''));
      setLastUpdatedTime(new Date());
      // Clear highlight after 1 second
      const timer = setTimeout(() => {
        setHighlightedSymbols((prev) => {
          const next = new Set(prev);
          next.delete(update.symbol || '');
          return next;
        });
      }, 1000);
      return () => clearTimeout(timer);
    }
  }, [priceUpdate.latest]);

  return { stocks, lastUpdatedTime, highlightedSymbols, marketStatus };
}

export default function Component(props: Props) {
  const { stocks, lastUpdatedTime, highlightedSymbols, marketStatus } = useComponent(props);

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="xl" padding={24}>
        <Stack gap={24}>
          {/* HEADER with title and last updated timestamp */}
          <Stack gap={12}>
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={1}>Market Watch</Heading>
              <Stack direction="horizontal" gap={8} align="center">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Last Updated: {lastUpdatedTime ? lastUpdatedTime.toLocaleTimeString() : 'Loading...'}
                </Text>
                {marketStatus.latest && (
                  <Badge
                    variant={marketStatus.latest.status === 'open' ? 'success' : 'default'}
                    size="sm"
                  >
                    {marketStatus.latest.status || 'unknown'}
                  </Badge>
                )}
              </Stack>
            </Stack>
          </Stack>

          {/* STOCK CARDS GRID */}
          {stocks.length > 0 ? (
            <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
              {stocks.map((stock) => {
                const isPositive = stock.changePercent >= 0;
                const isHighlighted = highlightedSymbols.has(stock.symbol);
                const changeColor = isPositive
                  ? 'var(--ggui-color-success-500, #22c55e)'
                  : 'var(--ggui-color-error-500, #ef4444)';

                return <StockCard key={stock.symbol} stock={stock} isHighlighted={isHighlighted} changeColor={changeColor} />;
              })}
            </CardGrid>
          ) : (
            <Box padding={32} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
              <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No stocks available. Loading data...
              </Text>
            </Box>
          )}
        </Stack>
      </Container>
    </>
  );
}
}

