interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// ── TYPES: define local types and interfaces here ──

// ── CONSTANTS: define constants, config, mappings here ──

// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──

function useComponent(props: Props) {
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // ── STATE: define useState hooks here ──
  const [currentStep, setCurrentStep] = useState<1 | 2 | 3>(1);
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [selectedAvatar, setSelectedAvatar] = useState(props.initialProfile.avatar || (props.avatarOptions && props.avatarOptions.length > 0 ? props.avatarOptions[0] : ''));
  const [role, setRole] = useState(props.initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme === 'dark');

  // ── CALLBACKS: define useCallback for event handlers ──
  const isStep1Valid = useCallback(() => name.trim() !== '' && email.trim() !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email), [name, email]);
  const isStep2Valid = useCallback(() => role !== '', [role]);

  const handleNext = useCallback(() => {
    if (currentStep === 1 && isStep1Valid()) {
      setCurrentStep(2);
    } else if (currentStep === 2 && isStep2Valid()) {
      setCurrentStep(3);
    }
  }, [currentStep, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((currentStep - 1) as 1 | 2 | 3);
    }
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    complete({
      name,
      email,
      avatar: selectedAvatar,
      role,
      emailNotifications,
      theme: theme ? 'dark' : 'light',
    });
  }, [complete, name, email, selectedAvatar, role, emailNotifications, theme]);

  return { currentStep, setCurrentStep, name, setName, email, setEmail, selectedAvatar, setSelectedAvatar, role, setRole, emailNotifications, setEmailNotifications, theme, setTheme, handleNext, handleBack, handleComplete, isStep1Valid, isStep2Valid };
}
export default function Component(props: Props) {
  const state = useComponent(props);

  const roleOptions = (props.roleOptions || []).map(r => ({ value: r, label: r }));

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={24}>
        {/* STEP INDICATOR */}
        <Stack gap={12}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2}>Profile Setup</Heading>
            <Badge variant="primary">Step {state.currentStep} of 3</Badge>
          </Stack>
          <Progress value={state.currentStep * 33.33} max={100} size="md" />
        </Stack>

        {/* STEP 1: PROFILE SETUP */}
        {state.currentStep === 1 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Step 1: Profile Setup</Heading>
              <Input label="Name" value={state.name} onChange={state.setName} placeholder="Enter your name" required />
              <Input label="Email" type="email" value={state.email} onChange={state.setEmail} placeholder="Enter your email" required error={state.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(state.email) ? 'Invalid email format' : ''} />
              <Stack gap={8}>
                <Text variant="label">Select Avatar</Text>
                <Row gap={8}>
                  {(props.avatarOptions || []).map((avatar) => (
                    <Box key={avatar} as={Clickable} onClick={() => state.setSelectedAvatar(avatar)} style={{ cursor: 'pointer', opacity: state.selectedAvatar === avatar ? 1 : 0.5, transition: 'opacity 200ms' }} padding={8} borderRadius="var(--ggui-shape-radius-md, 8px)" background={state.selectedAvatar === avatar ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'transparent'} border={state.selectedAvatar === avatar ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid var(--ggui-color-outline, #d4d4d8)'}>
                      <Text size="3xl">{avatar}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 2: PREFERENCES */}
        {state.currentStep === 2 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Step 2: Preferences</Heading>
              <Select label="Role" value={state.role} onChange={state.setRole} options={roleOptions} placeholder="Select your role" required />
              <Toggle label="Email Notifications" checked={state.emailNotifications} onChange={state.setEmailNotifications} />
              <Toggle label="Dark Theme" checked={state.theme} onChange={state.setTheme} />
            </Stack>
          </Card>
        )}

        {/* STEP 3: REVIEW & CONFIRM */}
        {state.currentStep === 3 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Step 3: Review & Confirm</Heading>
              <Divider />
              <Stack gap={12}>
                <Text variant="label">Name</Text>
                <Text>{state.name}</Text>
              </Stack>
              <Stack gap={12}>
                <Text variant="label">Email</Text>
                <Text>{state.email}</Text>
              </Stack>
              <Stack gap={12}>
                <Text variant="label">Avatar</Text>
                <Text size="2xl">{state.selectedAvatar}</Text>
              </Stack>
              <Stack gap={12}>
                <Text variant="label">Role</Text>
                <Text>{state.role}</Text>
              </Stack>
              <Stack gap={12}>
                <Text variant="label">Email Notifications</Text>
                <Text>{state.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
              </Stack>
              <Stack gap={12}>
                <Text variant="label">Theme</Text>
                <Text>{state.theme ? 'Dark' : 'Light'}</Text>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* NAVIGATION BUTTONS */}
        <Row gap={8} justify="between">
          {state.currentStep > 1 && (
            <Button variant="ghost" onClick={state.handleBack}>Go Back</Button>
          )}
          <Spacer size="flex" />
          {state.currentStep < 3 && (
            <Button variant="primary" onClick={state.handleNext} disabled={!state.isStep1Valid() && state.currentStep === 1 ? true : !state.isStep2Valid() && state.currentStep === 2 ? true : false}>Next</Button>
          )}
          {state.currentStep === 3 && (
            <Button variant="primary" onClick={state.handleComplete}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
